#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;

vector<int> g[N];
int up[N][20], dep[N], deg[N];
long long sum[N];

void dfs(int u, int p) {
    up[u][0] = p;
    dep[u] = dep[p] + 1;
    sum[u] = sum[p] + deg[u];
    for (int i = 1; i < 20; i++)
        up[u][i] = up[up[u][i-1]][i-1];
    for (int v : g[u]) {
        if (v != p) {
            dfs(v, u);
        }
    }
}

int lca(int x, int y) {
    if (dep[x] < dep[y]) swap(x, y);
    int diff = dep[x] - dep[y];
    for (int i = 0; i < 20; i++)
        if (diff >> i & 1)
            x = up[x][i];
    if (x == y) return x;
    for (int i = 19; i >= 0; i--)
        if (up[x][i] != up[y][i])
            x = up[x][i], y = up[y][i];
    return up[x][0];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;

    for (int i = 1; i < n; i++) {
        int x, y;
        cin >> x >> y;
        g[x].push_back(y);
        g[y].push_back(x);
        deg[x]++;
        deg[y]++;
    }

    dfs(1, 0);

    while (m--) {
        int u, v;
        cin >> u >> v;
        if (u == v) {
            cout << deg[u] << '\n';
            continue;
        }
        int l = lca(u, v);
        long long ans = sum[u] + sum[v] - sum[l] - sum[up[l][0]];
        cout << ans << '\n';
    }

    return 0;
}
